def binary_search(arr, target):
    low = 0
    high = len(arr) - 1
    found = False
    while low <= high:
        mid = (low + high) // 2
        if arr[mid] == target:
            found = True
            break
        elif arr[mid] < target:
            low = mid + 1
        else:
            high = mid - 1
    return found

